sql:
SELECT AVG(cell_count_norm_T0) AS avg_normalized_cell_count
FROM cell_counts
WHERE experiment_id = 1;

external_knowledge:
- 'Initial cell counts' refers to the first recorded cell count for each experiment; 
- 'Treatment details' include the treatment name and concentration; 
- 'Latest access information' refers to the most recent access log for each experiment, including the access date, type, IP address, and device used; 
- 'Change in cell count' is calculated by subtracting the previous cell count from the current cell count.

sql:
SELECT experiment_id, cell_count_norm_T0
FROM cell_counts
WHERE cell_count_method = 'automated';

SELECT AVG(G1_proportion) AS avg_g1_proportion
FROM cell_counts
WHERE experiment_id = 1;
